class Solution:
    def decode(self, encoded):
        n = len(encoded) + 1
        total = 0
        for v in range(1, n + 1):
            total ^= v
        odd = 0
        for i in range(1, len(encoded), 2):
            odd ^= encoded[i]
        first = total ^ odd
        perm = [first]
        for e in encoded:
            perm.append(perm[-1] ^ e)
        return perm

