var decode = function(encoded) {
    const n = encoded.length + 1;
    let total = 0;
    for (let v = 1; v <= n; v++) total ^= v;
    let odd = 0;
    for (let i = 1; i < encoded.length; i += 2) odd ^= encoded[i];
    let cur = total ^ odd;
    const res = [cur];
    for (const e of encoded) {
        cur ^= e;
        res.push(cur);
    }
    return res;
};
